$(document).ready(function(){$(".gallery").slick(),$(".review-gallery").slick({slidesToShow:3,slidesToScroll:1,responsive:[{breakpoint:767,settings:{slidesToShow:1,slidesToScroll:1}}]}),$("[data-click=scroll-to-target]").on("click",function(o){o.preventDefault(),o.stopPropagation();var e=$(this).attr("href");$("html, body").animate({scrollTop:$(e).offset().top},500)}),$("html, body").animate({scrollTop:$("#header-anchor").offset().top+40},400)});